changeSet.sql:
DROP INDEX IF EXISTS openconceptlab_item_url;
ALTER TABLE openconceptlab_item
    ALTER COLUMN hashed_url TYPE bytea
    USING NULL;
CREATE INDEX openconceptlab_item_url ON openconceptlab_item (hashed_url);

preConditions.sqlCheck:
SELECT CASE WHEN EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'concept_class'
      AND column_name = 'description' AND udt_name = 'oid'
) THEN 1 ELSE 0 END;

changeSet.sql:
ALTER TABLE concept_class
    ALTER COLUMN description TYPE text
    USING COALESCE(convert_from(lo_get(description), 'UTF8'), '');

